<CreateParticipant onSubmit={(formData) => {
  fetch("http://localhost:4000/api/participants", {
    method: "POST",
    body: formData,
  }).then(() => alert("Teilnehmer gespeichert!"));
}} />


export default function Participants() {
  return <CreateParticipant />;
}
